import{_ as a,o as e,c as i,a2 as r}from"./chunks/framework.QoSTM79V.js";const m=JSON.parse('{"title":"业务接入场景手册","description":"","frontmatter":{},"headers":[],"relativePath":"mango-docs/guides/business-integration/README.md","filePath":"mango-docs/guides/business-integration/README.md"}'),o={name:"mango-docs/guides/business-integration/README.md"};function l(d,t,n,s,h,c){return e(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="业务接入场景手册" tabindex="-1">业务接入场景手册 <a class="header-anchor" href="#业务接入场景手册" aria-label="Permalink to &quot;业务接入场景手册&quot;">​</a></h1><h2 id="_1-定位" tabindex="-1">1. 定位 <a class="header-anchor" href="#_1-定位" aria-label="Permalink to &quot;1. 定位&quot;">​</a></h2><p>本文面向基于 Mango 开发业务系统的开发者，用场景方式串起模块 README、能力地图和常见排障入口。</p><p>这里记录接入路径和检查点，不承载长期规范；正式交付规则以 PMO preflight 输出和 <code>mango-pmo/rules/**</code> 为准。</p><h2 id="_2-使用方式" tabindex="-1">2. 使用方式 <a class="header-anchor" href="#_2-使用方式" aria-label="Permalink to &quot;2. 使用方式&quot;">​</a></h2><ol><li>先按业务目标选择场景。</li><li>按阅读顺序打开模块 README，确认后端 starter、前端包、配置、菜单和验证入口。</li><li>按场景检查点完成业务代码接入。</li><li>用模块 README 的验证命令和场景验收点一起验证。</li></ol><h2 id="_3-场景索引" tabindex="-1">3. 场景索引 <a class="header-anchor" href="#_3-场景索引" aria-label="Permalink to &quot;3. 场景索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>适合问题</th><th>主要能力</th></tr></thead><tbody><tr><td><a href="./file-upload-form">文件上传表单</a></td><td>业务表单上传附件、回显、预览、删除失败</td><td>File、Fileproc、File Preview、Frontend File</td></tr><tr><td><a href="./workflow-business-approval">业务审批接入</a></td><td>业务单据发起审批、处理审批结果、查看流程记录</td><td>Workflow、Workflow Frontend、Workflow Example</td></tr><tr><td><a href="./rbac-menu-page-troubleshooting">菜单页面打不开排障</a></td><td>登录后菜单空白、404、页面组件找不到</td><td>Authorization、RBAC、Admin Shell</td></tr><tr><td><a href="./permission-button-troubleshooting">按钮权限不显示排障</a></td><td>菜单可见但新增、编辑、删除按钮不显示</td><td>Authorization、Access、RBAC Frontend</td></tr><tr><td><a href="./tenant-dict-config-empty">租户字典配置为空排障</a></td><td>业务下拉、字典、配置或基础数据为空</td><td>Identity、Org、System、Seed</td></tr></tbody></table><h2 id="_4-新场景登记门禁" tabindex="-1">4. 新场景登记门禁 <a class="header-anchor" href="#_4-新场景登记门禁" aria-label="Permalink to &quot;4. 新场景登记门禁&quot;">​</a></h2><p>新增业务接入场景时，README 需要说清楚：</p><ul><li>业务目标是什么，哪些模块参与。</li><li>后端需要引入哪些 starter 或 remote starter。</li><li>前端需要引入哪些包，是否只适用于管理后台。</li><li>配置项在哪里配置，默认值是什么。</li><li>菜单、权限、租户、初始化数据由谁负责。</li><li>最小验收闭环是什么，失败时先查哪张表或哪个接口。</li></ul><h2 id="_5-关联入口" tabindex="-1">5. 关联入口 <a class="header-anchor" href="#_5-关联入口" aria-label="Permalink to &quot;5. 关联入口&quot;">​</a></h2><ul><li><a href="./../../capabilities/README">Mango 能力地图</a></li><li><a href="./../../designs/business-project-development-guide">业务项目开发指南</a></li><li><a href="./../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../../mango-pmo/rules/06-document-assets">文档资产归档边界</a></li></ul>',13)])])}const p=a(o,[["render",l]]);export{m as __pageData,p as default};
